formulas.expression:
CASE(
    TEXT({!$Record.FrecuenciaCompra__c}),
    /* Mensual: primer día del mes actual */
    "Mensual", DATE( YEAR(TODAY()), MONTH(TODAY()), 1 ),
    /* Bimensual: primer día del mes anterior */
    "Bimensual",
        IF(
            MONTH(TODAY()) - 1 > 0,
            DATE( YEAR(TODAY()), MONTH(TODAY()) - 1, 1 ),
            /* Si es enero, retrocede un año y asigna diciembre */
            DATE( YEAR(TODAY()) - 1, MONTH(TODAY()) - 1 + 12, 1 )
        ),
    /* Trimestral: primer día de hace 2 meses */
    "Trimestral",
        IF(
            MONTH(TODAY()) - 2 > 0,
            DATE( YEAR(TODAY()), MONTH(TODAY()) - 2, 1 ),
            DATE( YEAR(TODAY()) - 1, MONTH(TODAY()) - 2 + 12, 1 )
        ),
    /* Semestral: primer día de hace 5 meses */
    "Semestral",
        IF(
            MONTH(TODAY()) - 5 > 0,
            DATE( YEAR(TODAY()), MONTH(TODAY()) - 5, 1 ),
            DATE( YEAR(TODAY()) - 1, MONTH(TODAY()) - 5 + 12, 1 )
        ),
    /* Anual: primer día del mismo mes del año anterior */
    "Anual", DATE( YEAR(TODAY()) - 1, MONTH(TODAY()), 1 ),
    /* Valor por defecto: Mensual */
    DATE( YEAR(TODAY()), MONTH(TODAY()), 1 )
)
